import Landing from './components/layout/Landing';
import './App.css';

const App = () => (
  <Router>
    <Fragment>
      <Navbar />
      <Landing />
      <Route exact path ="/" Componentomponent

      ={ Landing } />
    </Fragment>
  </Router>

);


export default App;
